import{_ as c,C as o,o as n,c as s,j as e,a as d,E as a,ag as l}from"./chunks/framework.HG0H2VLS.js";const w=JSON.parse('{"title":"Datatables","description":"","frontmatter":{},"headers":[],"relativePath":"components/datatables.md","filePath":"components/datatables.md"}'),b={name:"components/datatables.md"},p={id:"datatables",tabindex:"-1"};function g(h,t,u,m,x,f){const i=o("Badge"),r=o("ComponentDemo");return n(),s("div",null,[t[3]||(t[3]=e("hr",null,null,-1)),t[4]||(t[4]=e("h2",{id:"title-datatables",tabindex:"-1"},[d("title: Datatables "),e("a",{class:"header-anchor",href:"#title-datatables","aria-label":'Permalink to "title: Datatables"'},"​")],-1)),e("h1",p,[t[0]||(t[0]=d("Datatables ",-1)),a(i,{type:"info",text:"Design System"}),t[1]||(t[1]=d()),t[2]||(t[2]=e("a",{class:"header-anchor",href:"#datatables","aria-label":'Permalink to "Datatables <Badge type="info" text="Design System" />"'},"​",-1))]),t[5]||(t[5]=e("blockquote",null,[e("p",null,"6 variants: Type (Pagination/Search) × Device (Desktop/Mobile) × Overflow (Scroll/Trigger; Trigger is mobile-only)")],-1)),a(r,{src:"/demos/src/components/Datatables/Datatables.html"}),t[6]||(t[6]=l('<h2 id="variant-matrix-6-variants" tabindex="-1">Variant matrix (6 variants) <a class="header-anchor" href="#variant-matrix-6-variants" aria-label="Permalink to &quot;Variant matrix (6 variants)&quot;">​</a></h2><p>Properties: <strong>Type × Device × Overflow Content</strong>.</p><table tabindex="0"><thead><tr><th>Node ID</th><th>Type</th><th>Device</th><th>Overflow Content</th><th>Built</th></tr></thead><tbody><tr><td>2562:8288</td><td>Pagination</td><td>Desktop</td><td>Scroll</td><td>✅ via base <code>.datatables</code></td></tr><tr><td>2562:8284</td><td>Pagination</td><td>Mobile</td><td>Scroll</td><td>✅ via <code>.datatables.datatables--mobile-scroll</code></td></tr><tr><td>2562:8286</td><td>Pagination</td><td>Mobile</td><td>Trigger</td><td>✅ via row markup with <code>.datatables__row</code> + <code>.datatables__row-detail</code> pairs</td></tr><tr><td>2562:8287</td><td>Search</td><td>Desktop</td><td>Scroll</td><td>✅ via base <code>.datatables</code> (toolbar swapped for search input + View/Export buttons)</td></tr><tr><td>2562:8285</td><td>Search</td><td>Mobile</td><td>Scroll</td><td>✅ via <code>.datatables.datatables--mobile-scroll</code></td></tr><tr><td>2562:8283</td><td>Search</td><td>Mobile</td><td>Trigger</td><td>✅ via kebab row markup</td></tr></tbody></table><p>Type × Device are pure layout/style differences. Overflow Content is a markup difference: Scroll uses normal table rows; Trigger uses paired <code>&lt;tr&gt;</code> rows where the second row holds a hidden <code>&lt;dl&gt;</code> revealed when its sibling row&#39;s kebab checkbox is checked.</p><h2 id="composition" tabindex="-1">Composition <a class="header-anchor" href="#composition" aria-label="Permalink to &quot;Composition&quot;">​</a></h2><p>Datatables <strong>wraps the Table component</strong> — the inner <code>&lt;table class=&quot;table&quot;&gt;…&lt;/table&gt;</code> uses the production Table CSS for cell padding, header bg, dividers, etc. Datatables only adds the surrounding chrome:</p><ul><li><code>Button</code> (<code>src/components/Button/</code>) — toolbar actions and Delete-style buttons</li><li><code>Input</code> (<code>src/components/Input/</code>) — search field</li><li><code>Table</code> (<code>src/components/Table/</code>) — base table presentation</li></ul><h2 id="notes-inconsistencies" tabindex="-1">Notes / Inconsistencies <a class="header-anchor" href="#notes-inconsistencies" aria-label="Permalink to &quot;Notes / Inconsistencies&quot;">​</a></h2><ul><li><strong>Header text colour discrepancy across variants.</strong> Figma binds the header <code>&lt;th&gt;</code> text to <code>--ai-text-primary</code> in some variants (Pagination Desktop) and <code>--ai-text-secondary</code> in others (Search Mobile, sometimes a single column within Pagination Mobile). The component normalises to <code>--ai-text-secondary</code> everywhere — inheriting the existing Table component&#39;s choice. Worth flagging to the designer.</li><li><strong>Layout via absolute positioning in Figma.</strong> Figma renders cells with absolute positioning + hardcoded pixel widths (e.g. <code>w-[356.469px]</code>). The production CSS uses native <code>&lt;table&gt;</code> with <code>border-collapse: collapse</code> and lets the browser distribute column widths — semantic, accessible, and resilient to content variation.</li><li><strong>Mobile scroll-indicator pill.</strong> The Mobile/Scroll variants in Figma include a small <code>bg-[var(--ai-surface-secondary)] h-[10px] rounded-full w-[180px]</code> pill at the bottom — a visual stand-in for the scrollbar. The production component uses the browser&#39;s native scrollbar.</li><li><strong>Pagination Mobile Trigger meta is just text</strong> (&quot;10 of 1,289&quot;) — no row-count select. Smaller toolbar to save space when the row layout already collapses to kebab.</li><li><strong>Search Desktop uses a primary Export button</strong> (with <code>download</code> icon); the Pagination variants use tertiary buttons throughout. The component HTML demos reflect both patterns.</li></ul><h2 id="interactivity" tabindex="-1">Interactivity <a class="header-anchor" href="#interactivity" aria-label="Permalink to &quot;Interactivity&quot;">​</a></h2><ul><li><strong>Kebab row expand</strong>: pure CSS via <code>:has(.datatables__kebab__input:checked) + .datatables__row-detail</code>. No JS; no popover dismiss; multiple rows can be open simultaneously. Each kebab is independent.</li><li><strong>Sort buttons, pagination, page-size select</strong>: visual only — actual sorting/pagination/page-size behaviour is the consumer&#39;s responsibility.</li></ul><h2 id="css-classes" tabindex="-1">CSS Classes <a class="header-anchor" href="#css-classes" aria-label="Permalink to &quot;CSS Classes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma element</th><th>CSS class</th><th>Notes</th></tr></thead><tbody><tr><td>Outer container</td><td><code>.datatables</code></td><td>White bg, secondary border, <code>--ai-radius-md</code>, <code>overflow: hidden</code>. Replaces <code>.table-wrap</code> from the Table component.</td></tr><tr><td>Mobile-scroll wrap</td><td><code>.datatables.datatables--mobile-scroll</code></td><td>Adds <code>max-width: 24rem</code> + <code>overflow-x: auto</code>; inner <code>.table</code> grows to <code>width: max-content</code> with <code>nowrap</code> cells</td></tr><tr><td>Toolbar</td><td><code>.datatables__toolbar</code></td><td>Flex row, white bg, bottom border. Padding <code>12/16</code> (vertical/horizontal)</td></tr><tr><td>Toolbar meta (left side)</td><td><code>.datatables__meta</code></td><td>Inline flex with text + <code>.datatables__select</code> for the row-count picker</td></tr><tr><td>Page-size select</td><td><code>.datatables__select</code></td><td>Button styled as a small select (32px tall, <code>--ai-radius-md</code>, chevron-down). Native <code>&lt;select&gt;</code> doesn&#39;t capture cleanly in Figma so this is a button</td></tr><tr><td>Toolbar search field</td><td><code>.datatables__search</code></td><td>Wraps the existing Input component; constrains to ≤18rem on desktop, full-width on mobile</td></tr><tr><td>Toolbar actions (right side)</td><td><code>.datatables__actions</code></td><td>Flex row of action buttons (uses Button component)</td></tr><tr><td>Sortable column header</td><td><code>&lt;button class=&quot;datatables__sort&quot;&gt;</code></td><td>Slots inside <code>&lt;th&gt;</code>; <code>--active</code> modifier flips the chevron icon to dark</td></tr><tr><td>Footer (pagination)</td><td><code>.datatables__footer</code></td><td>Flex row, white bg, top border. Padding <code>8-9/16</code></td></tr><tr><td>Pagination button group</td><td><code>.datatables__pagination</code></td><td>Connected segmented buttons inside a single radius-md outline</td></tr><tr><td>Pagination button</td><td><code>.datatables__page-btn</code></td><td>40×40 cells. <code>--active</code> modifier paints <code>--ai-surface-secondary</code> background with bold text</td></tr><tr><td>Kebab toggle (Trigger only)</td><td><code>&lt;label class=&quot;datatables__kebab&quot;&gt;</code></td><td>Wraps a hidden checkbox + <code>more-vertical</code> icon</td></tr><tr><td>Kebab cell</td><td><code>.datatables__kebab-cell</code></td><td>Last <code>&lt;th&gt;</code>/<code>&lt;td&gt;</code> column, fixed 48px wide</td></tr><tr><td>Visible row</td><td><code>&lt;tr class=&quot;datatables__row&quot;&gt;</code></td><td>Pairs with the next sibling row</td></tr><tr><td>Detail row</td><td><code>&lt;tr class=&quot;datatables__row-detail&quot;&gt;</code></td><td>Hidden by default; revealed when the prev row&#39;s kebab input is <code>:checked</code></td></tr><tr><td>Detail definition list</td><td><code>&lt;dl class=&quot;datatables__detail-list&quot;&gt;</code></td><td>2-column grid of <code>&lt;dt&gt;</code> (uppercase label) / <code>&lt;dd&gt;</code> (value) pairs</td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma value</th><th>CSS variable</th><th>Role</th></tr></thead><tbody><tr><td><code>surface/elevated-1</code></td><td><code>--ai-surface-elevated-1</code></td><td>Container bg, toolbar bg, footer bg, select bg</td></tr><tr><td><code>surface/minimal</code></td><td><code>--ai-surface-minimal</code></td><td>Page-btn hover, expanded row bg, detail-row bg</td></tr><tr><td><code>surface/secondary</code></td><td><code>--ai-surface-secondary</code></td><td>Active pagination button bg</td></tr><tr><td><code>border/secondary</code></td><td><code>--ai-border-secondary</code></td><td>All container/toolbar/footer borders, divider lines</td></tr><tr><td><code>text/primary</code></td><td><code>--ai-text-primary</code></td><td>Body text, page-btn label, sort-active icon</td></tr><tr><td><code>text/secondary</code></td><td><code>--ai-text-secondary</code></td><td>(inherited via Table) Header text</td></tr><tr><td><code>text/contrast</code></td><td><code>--ai-text-contrast</code></td><td>Toolbar meta text, footer text, detail-list <code>&lt;dt&gt;</code></td></tr><tr><td><code>icon/contrast</code></td><td><code>--ai-icon-contrast</code></td><td>Sort-icon (inactive), kebab icon, select chevron</td></tr><tr><td><code>radius/md</code> (8px)</td><td><code>--ai-radius-md</code></td><td>Container, select, kebab, page-btn group</td></tr><tr><td><code>spacing/2</code> (6px)</td><td><code>--ai-spacing-2</code></td><td>Meta gap, kebab→label gap</td></tr><tr><td><code>spacing/3</code> (8px)</td><td><code>--ai-spacing-3</code></td><td>Action gap, footer padding-y, select padding-x</td></tr><tr><td><code>spacing/4</code> (12px)</td><td><code>--ai-spacing-4</code></td><td>Toolbar gap, padding-y</td></tr><tr><td><code>spacing/5</code> (16px)</td><td><code>--ai-spacing-5</code></td><td>Toolbar/footer padding-x, detail-list column gap</td></tr><tr><td><code>spacing/7</code> (32px)</td><td><code>--ai-spacing-7</code></td><td>Select height</td></tr><tr><td><code>spacing/8</code> (40px)</td><td><code>--ai-spacing-8</code></td><td>Page-btn cell size</td></tr><tr><td><code>spacing/9</code> (48px)</td><td><code>--ai-spacing-9</code></td><td>Kebab cell width</td></tr><tr><td><code>font/title</code></td><td><code>--ai-font-title</code></td><td>All Datatables-specific text</td></tr><tr><td><code>font/fixed-xs</code> (14px)</td><td><code>--ai-font-fixed-xs</code></td><td>Footer text, meta text, page-btn label</td></tr><tr><td><code>font/fixed-xxs</code> (12px)</td><td><code>--ai-font-fixed-xxs</code></td><td>Detail <code>&lt;dt&gt;</code> (uppercase labels)</td></tr><tr><td><code>font/medium</code></td><td><code>--ai-font-medium</code></td><td>Page-size select label</td></tr><tr><td><code>font/bold</code></td><td><code>--ai-font-bold</code></td><td>Active page-btn, footer <code>&lt;strong&gt;</code></td></tr><tr><td><code>tracking/7</code> (0.05em)</td><td><code>--ai-tracking-7</code></td><td>Detail <code>&lt;dt&gt;</code> letter-spacing</td></tr></tbody></table><h2 id="token-gaps" tabindex="-1">Token Gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token Gaps&quot;">​</a></h2><p>None — every value maps to an existing <code>--ai-*</code> token.</p><h2 id="figma" tabindex="-1">Figma <a class="header-anchor" href="#figma" aria-label="Permalink to &quot;Figma&quot;">​</a></h2><p><a href="https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=2562-8289" target="_blank" rel="noreferrer">Open in Figma</a></p>',19))])}const y=c(b,[["render",g]]);export{w as __pageData,y as default};
